class Solution:
    def minWindow(self, s, t):
        from collections import Counter
        need = Counter(t)
        n = len(s)
        best = ''
        for i in range(n):
            cnt = Counter()
            for j in range(i, n):
                cnt[s[j]] += 1
                if all(cnt[c] >= need[c] for c in need):
                    cand = s[i:j + 1]
                    if best == '' or len(cand) < len(best):
                        best = cand
                    break
        return best

